   302→        if (typeIsUnchanged && wouldSameTypeBeInferred) {
   303→          context.report({
   304→            node,
   305→            messageId: 'unnecessaryAssertion',
   306→            fix(fixer) {
   307→              if (node.type === AST_NODE_TYPES.TSTypeAssertion) {
   308→                const openingAngleBracket = nullThrows(
   309→                  context.sourceCode.getTokenBefore(
   310→                    node.typeAnnotation,
   311→                    token =>
   312→                      token.type === AST_TOKEN_TYPES.Punctuator &&
   313→                      token.value === '<',
   314→                  ),
   315→                  NullThrowsReasons.MissingToken('<', 'type annotation'),
   316→                );
   317→                const closingAngleBracket = nullThrows(
   318→                  context.sourceCode.getTokenAfter(
   319→                    node.typeAnnotation,
   320→                    token =>
   321→                      token.type === AST_TOKEN_TYPES.Punctuator &&
   322→                      token.value === '>',
   323→                  ),
   324→                  NullThrowsReasons.MissingToken('>', 'type annotation'),
   325→                );
   326→
   327→                // < ( number ) > ( 3 + 5 )
   328→                // ^---remove---^
   329→                return fixer.removeRange([
   330→                  openingAngleBracket.range[0],
   331→                  closingAngleBracket.range[1],
   332→                ]);
   333→              }
   334→              // `as` is always present in TSAsExpression
   335→              const asToken = nullThrows(
   336→                context.sourceCode.getTokenAfter(
   337→                  node.expression,
   338→                  token =>
   339→                    token.type === AST_TOKEN_TYPES.Identifier &&
   340→                    token.value === 'as',
   341→                ),
   342→                NullThrowsReasons.MissingToken('>', 'type annotation'),
   343→              );
   344→              const tokenBeforeAs = nullThrows(
   345→                context.sourceCode.getTokenBefore(asToken, {
   346→                  includeComments: true,
   347→                }),
   348→                NullThrowsReasons.MissingToken('comment', 'as'),
   349→              );
   350→
   351→              // ( 3 + 5 )  as  number
   352→              //          ^--remove--^
   353→              return fixer.removeRange([tokenBeforeAs.range[1], node.range[1]]);
   354→            },
   355→          });
   356→        }
   357→
   358→        // TODO - add contextually unnecessary check for this
   359→      },
   360→      TSNonNullExpression(node): void {
   361→        const removeExclamationFix: ReportFixFunction = fixer => {
   362→          const exclamationToken = nullThrows(
   363→            context.sourceCode.getLastToken(node, token => token.value === '!'),
   364→            NullThrowsReasons.MissingToken(
   365→              'exclamation mark',
   366→              'non-null assertion',
   367→            ),
   368→          );
   369→
   370→          return fixer.removeRange(exclamationToken.range);
   371→        };
   372→
   373→        if (
   374→          node.parent.type === AST_NODE_TYPES.AssignmentExpression &&
   375→          node.parent.operator === '='
   376→        ) {
   377→          if (node.parent.left === node) {
   378→            context.report({
   379→              node,
   380→              messageId: 'contextuallyUnnecessary',
   381→              fix: removeExclamationFix,
   382→            });
   383→          }
   384→          // for all other = assignments we ignore non-null checks
   385→          // this is because non-null assertions can change the type-flow of the code
   386→          // so whilst they might be unnecessary for the assignment - they are necessary
   387→          // for following code
   388→          return;
   389→        }
   390→
   391→        const originalNode = services.esTreeNodeToTSNodeMap.get(node);
   392→
   393→        const constrainedType = getConstrainedTypeAtLocation(
   394→          services,
   395→          node.expression,
   396→        );
   397→        const actualType = services.getTypeAtLocation(node.expression);
   398→
   399→        // Check both the constrained type and the actual type.
   400→        // If either is nullable, we should not report the assertion as unnecessary.
   401→        // This handles cases like generic constraints with `any` where the
   402→        // constrained type is `any` (nullable) but the actual type might be
   403→        // a type parameter that TypeScript treats nominally.
   404→        // See: https://github.com/typescript-eslint/typescript-eslint/issues/11559
   405→        const constrainedTypeIsNullable = isNullableType(constrainedType);
   406→        const actualTypeIsNullable = isNullableType(actualType);
   407→
   408→        if (!constrainedTypeIsNullable && !actualTypeIsNullable) {
   409→          if (
   410→            node.expression.type === AST_NODE_TYPES.Identifier &&
   411→            isPossiblyUsedBeforeAssigned(node.expression)
   412→          ) {
   413→            return;
   414→          }
   415→
   416→          context.report({
   417→            node,
   418→            messageId: 'unnecessaryAssertion',
   419→            fix: removeExclamationFix,
   420→          });
   421→        } else {
   422→          // we know it's a nullable type
   423→          // so figure out if the variable is used in a place that accepts nullable types
   424→
   425→          // If the constrained type differs from the actual type (e.g., when dealing
   426→          // with unresolved generic type parameters), we should not report the assertion
   427→          // as contextually unnecessary. TypeScript may still require the assertion
   428→          // even if the constraint is nullable (like `any`).
   429→          // See: https://github.com/typescript-eslint/typescript-eslint/issues/11559
   430→          if (constrainedType !== actualType) {
   431→            return;
   432→          }
   433→
   434→          const contextualType = getContextualType(checker, originalNode);
   435→          if (contextualType) {
   436→            if (
   437→              isTypeFlagSet(constrainedType, ts.TypeFlags.Unknown) &&
   438→              !isTypeFlagSet(contextualType, ts.TypeFlags.Unknown)
   439→            ) {
   440→              return;
   441→            }
   442→
   443→            // in strict mode you can't assign null to undefined, so we have to make sure that
   444→            // the two types share a nullable type
   445→            const typeIncludesUndefined = isTypeFlagSet(
   446→              constrainedType,
   447→              ts.TypeFlags.Undefined,
   448→            );
   449→            const typeIncludesNull = isTypeFlagSet(
   450→              constrainedType,
   451→              ts.TypeFlags.Null,
   452→            );
   453→            const typeIncludesVoid = isTypeFlagSet(
   454→              constrainedType,
   455→              ts.TypeFlags.Void,
   456→            );
   457→
   458→            const contextualTypeIncludesUndefined = isTypeFlagSet(
   459→              contextualType,
   460→              ts.TypeFlags.Undefined,
   461→            );
   462→            const contextualTypeIncludesNull = isTypeFlagSet(
   463→              contextualType,
   464→              ts.TypeFlags.Null,
   465→            );
   466→            const contextualTypeIncludesVoid = isTypeFlagSet(
   467→              contextualType,
   468→              ts.TypeFlags.Void,
   469→            );
   470→
   471→            // make sure that the parent accepts the same types
   472→            // i.e. assigning `string | null | undefined` to `string | undefined` is invalid
   473→            const isValidUndefined = typeIncludesUndefined
   474→              ? contextualTypeIncludesUndefined
   475→              : true;
   476→            const isValidNull = typeIncludesNull
   477→              ? contextualTypeIncludesNull
   478→              : true;
   479→            const isValidVoid = typeIncludesVoid
   480→              ? contextualTypeIncludesVoid
   481→              : true;
   482→
   483→            if (isValidUndefined && isValidNull && isValidVoid) {
   484→              context.report({
   485→                node,
   486→                messageId: 'contextuallyUnnecessary',
   487→                fix: removeExclamationFix,
   488→              });
   489→            }
   490→          }
   491→        }
   492→      },
   493→    };
   494→  },
   495→});
   496→

